#include <stdio.h>
int maxCoins(int* nums, int numsSize) {
    int n = numsSize + 2;
    int* newNums = (int*)malloc(n * sizeof(int));
    newNums[0] = 1;
    newNums[n - 1] = 1;
    for (int i = 0; i < numsSize; i++) {
        newNums[i + 1] = nums[i];
    }
    int** dp = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        dp[i] = (int*)malloc(n * sizeof(int));
    }
    for (int length = 1; length < n; length++) {
        for (int i = 0; i < n - length; i++) {
            int j = i + length;
            int maxCoins = 0;
            for (int k = i; k <= j; k++) {
                int coins = newNums[i] * newNums[k] * newNums[j + 1];
                if (k > i) coins += dp[i][k - 1];
                if (k < j) coins += dp[k + 1][j];
                maxCoins = maxCoins > coins ? maxCoins : coins;
            }
            dp[i][j] = maxCoins;
        }
    }
    int result = dp[0][n - 1];
    free(newNums);
    for (int i = 0; i < n; i++) {
        free(dp[i]);
    }
    free(dp);
    return result;
}

